{
    static void Main()
    {
        List<int> numbers = new List<int> { 1, 2, 3, 4 };

        var result = numbers.Where(n => n > 10);

        var firstNumber = result.FirstOrDefault();

        if (firstNumber != default(int)) // or simply if (firstNumber != 0) for int type
        {
            Console.WriteLine(firstNumber);
        }
        else
        {
            Console.WriteLine("No numbers greater than 10 found.");
        }
    }
}
```

