        numbers.add(2);
        numbers.add(3);
        numbers.add(4);

        Iterator<Integer> iterator = numbers.iterator();
        while (iterator.hasNext()) {
            int n = iterator.next();
            if (n > 2) {
                iterator.remove(); // Safe removal during iteration
            }
        }

        System.out.println(numbers); // Output: [1, 2]
    }
}
```

---

